import{_ as s,o as a,c as i,a2 as n}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"File Descriptor、阻塞/非阻塞、I/O Multiplexing 与 epoll","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/notes/05-linux-network/06-file-descriptor-nonblocking-epoll.md","filePath":"05-backend-data/notes/05-linux-network/06-file-descriptor-nonblocking-epoll.md","lastUpdated":1784542968000}'),l={name:"05-backend-data/notes/05-linux-network/06-file-descriptor-nonblocking-epoll.md"};function t(p,e,d,r,o,c){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="file-descriptor、阻塞-非阻塞、i-o-multiplexing-与-epoll" tabindex="-1">File Descriptor、阻塞/非阻塞、I/O Multiplexing 与 epoll <a class="header-anchor" href="#file-descriptor、阻塞-非阻塞、i-o-multiplexing-与-epoll" aria-label="Permalink to &quot;File Descriptor、阻塞/非阻塞、I/O Multiplexing 与 epoll&quot;">​</a></h1><p>文件描述符把进程中的小整数连接到内核打开对象；非阻塞 I/O 与 epoll 让一个执行线程在大量连接之间只处理当前可推进的工作。</p><h2 id="_1-fd、fd-表与-open-file-description" tabindex="-1">1. fd、fd 表与 open file description <a class="header-anchor" href="#_1-fd、fd-表与-open-file-description" aria-label="Permalink to &quot;1. fd、fd 表与 open file description&quot;">​</a></h2><p>fd 是进程文件描述符表的索引，不是文件本身。表项指向内核的 open file description，后者保存当前文件偏移、状态标志等；open file description 再引用 inode、socket 等对象。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F3[&quot;fd 3&quot;] --&gt; O1[&quot;open file description：offset、status flags&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F4[&quot;dup 后 fd 4&quot;] --&gt; O1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O1 --&gt; I[&quot;inode 或 socket&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F7[&quot;另一次 open 的 fd 7&quot;] --&gt; O2[&quot;另一个 open file description&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O2 --&gt; I</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><code>dup</code> 产生的新 fd 共享文件偏移和 <code>O_NONBLOCK</code> 等 file status flags，但每个 fd 自己有 <code>FD_CLOEXEC</code>。另一次 <code>open</code> 通常创建独立 open file description，即使路径相同也可有独立偏移。</p><p>fd 数字会复用。线程 A close fd 8 后，线程 B 新 open 可能立即得到 8；保存裸整数跨并发生命周期会把操作发给错误对象。所有权设计应明确谁关闭、何时不再使用。</p><h2 id="_2-创建、继承与关闭" tabindex="-1">2. 创建、继承与关闭 <a class="header-anchor" href="#_2-创建、继承与关闭" aria-label="Permalink to &quot;2. 创建、继承与关闭&quot;">​</a></h2><p><code>open</code>、<code>socket</code>、<code>accept</code>、<code>pipe</code> 等返回新 fd。fork 后子进程继承指向相同 open file description 的表项；exec 默认保留 fd，除非设置 close-on-exec。</p><p>优先在创建时原子设置：<code>open(..., O_CLOEXEC)</code>、<code>socket(..., SOCK_CLOEXEC)</code>、<code>accept4(..., SOCK_CLOEXEC|SOCK_NONBLOCK)</code>。先创建再 <code>fcntl</code> 的两步在多线程 fork/exec 间可能竞态泄漏。</p><p><code>close</code> 释放当前 fd 引用，但内核对象会在最后一个引用关闭后销毁。close 的错误处理有平台差异；Linux 上即使 close 报错，fd 通常已释放，盲目重试可能关闭已复用的新 fd。需要持久化保证时，在 close 前显式 <code>fsync</code> 并处理错误。</p><h2 id="_3-限制与泄漏" tabindex="-1">3. 限制与泄漏 <a class="header-anchor" href="#_3-限制与泄漏" aria-label="Permalink to &quot;3. 限制与泄漏&quot;">​</a></h2><p>进程受 <code>RLIMIT_NOFILE</code> 软/硬限制，系统还有全局文件表限制。耗尽时 open/accept 可能返回 <code>EMFILE</code>（进程限制）或 <code>ENFILE</code>（系统限制）。</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ulimit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Sn</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ulimit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Hn</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;open files&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/proc/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/limits&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/proc/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/fd&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mindepth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -maxdepth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> wc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/sys/fs/file-nr</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>不要在生产直接提高到极大值；每个连接还消耗内核内存、应用缓冲和下游资源。先按类型统计 fd，找出未关闭响应体、文件、pipe 或连接。</p><p><code>/proc/PID/fd</code> 的符号链接目标可含敏感路径；并发关闭会让遍历结果变化。macOS 使用 <code>launchctl limit maxfiles</code>、<code>ulimit</code> 与 <code>lsof</code>，没有 Linux <code>/proc</code>。</p><h2 id="_4-阻塞-i-o" tabindex="-1">4. 阻塞 I/O <a class="header-anchor" href="#_4-阻塞-i-o" aria-label="Permalink to &quot;4. 阻塞 I/O&quot;">​</a></h2><p>阻塞 fd 上的 <code>read</code> 在没有数据时可让调用线程睡眠；有数据时也允许短读。普通磁盘文件即使设置 <code>O_NONBLOCK</code>，通常仍可在 page fault 或存储路径阻塞，因为该标志主要对 pipe、FIFO、socket、设备等有意义。</p><p>阻塞简单且适合少量连接或线程/协程模型，但必须有超时与取消。socket 的读超时、请求 deadline 和业务 deadline 各自边界不同；只设置 connect timeout 不能限制响应读取。</p><h2 id="_5-非阻塞-i-o" tabindex="-1">5. 非阻塞 I/O <a class="header-anchor" href="#_5-非阻塞-i-o" aria-label="Permalink to &quot;5. 非阻塞 I/O&quot;">​</a></h2><p>设置 <code>O_NONBLOCK</code> 后，当前无法推进的调用返回 <code>EAGAIN</code>/<code>EWOULDBLOCK</code>，调用者保留状态并等待下次就绪。它不保证操作永不耗时，也不把多步协议自动变成异步。</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> flags </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> fcntl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, F_GETFL, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (flags </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> fcntl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, F_SETFL, flags </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> O_NONBLOCK) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    /* 记录 errno 并关闭 fd */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>不能直接用 <code>F_SETFL, O_NONBLOCK</code> 覆盖原 flags，否则可能清除 <code>O_APPEND</code> 等状态。多个引用同一 open file description 时，<code>O_NONBLOCK</code> 的变化可影响共享者。</p><p>非阻塞 read 的分支：<code>n&gt;0</code> 消费字节；<code>n==0</code> 表示流式对端有序 EOF；<code>-1/EAGAIN</code> 表示暂时无数据；其他错误进入关闭/恢复。write 也可能部分成功，未写部分必须排队，并设置每连接上限实现背压。</p><h2 id="_6-i-o-multiplexing" tabindex="-1">6. I/O multiplexing <a class="header-anchor" href="#_6-i-o-multiplexing" aria-label="Permalink to &quot;6. I/O multiplexing&quot;">​</a></h2><p><code>select</code>、<code>poll</code>、epoll 都等待多个 fd 的就绪状态。“就绪”表示某操作现在可能不阻塞，不表示完整应用消息已经到达，也不表示后续调用必然成功；在通知与操作间状态可改变。</p><table tabindex="0"><thead><tr><th>接口</th><th>模型</th><th>主要边界</th></tr></thead><tbody><tr><td><code>select</code></td><td>每次传入位集合</td><td>fd 编号受 <code>FD_SETSIZE</code>，每次复制和扫描</td></tr><tr><td><code>poll</code></td><td>每次传入 fd 数组</td><td>无 select 编号上限，但每轮线性扫描</td></tr><tr><td><code>epoll</code></td><td>内核维护 interest list，返回 ready list</td><td>Linux 专用；需正确处理生命周期和触发模式</td></tr></tbody></table><p>macOS/BSD 使用 kqueue；Windows 有 IOCP。业务代码应优先使用成熟运行时/框架的事件循环，不为“性能”手写一个缺少取消、背压和测试的 poller。</p><h2 id="_7-epoll-的对象与操作" tabindex="-1">7. epoll 的对象与操作 <a class="header-anchor" href="#_7-epoll-的对象与操作" aria-label="Permalink to &quot;7. epoll 的对象与操作&quot;">​</a></h2><p><code>epoll_create1(EPOLL_CLOEXEC)</code> 创建 epoll fd；<code>epoll_ctl</code> ADD/MOD/DEL 管理 interest list；<code>epoll_wait</code> 返回 ready events。被监视对象由 fd 与其 open file description 组合识别，dup 和 close 的行为需要谨慎。</p><p>常见 event：</p><ul><li><code>EPOLLIN</code>：可读、监听 socket 可 accept、或对端关闭导致读到 EOF。</li><li><code>EPOLLOUT</code>：可写；连接非阻塞建立完成也会通知，必须用 <code>SO_ERROR</code> 检查成功与失败。</li><li><code>EPOLLERR</code>/<code>EPOLLHUP</code>：错误/挂起，即使未显式请求也可能报告；仍应读取错误或 drain 数据。</li><li><code>EPOLLRDHUP</code>：stream 对端关闭写半边，适合检测 half-close。</li><li><code>EPOLLET</code>：edge-triggered；只在状态边缘通知。</li><li><code>EPOLLONESHOT</code>：一次通知后禁用，处理完成需 MOD rearm。</li></ul><h2 id="_8-level-triggered-与-edge-triggered" tabindex="-1">8. level-triggered 与 edge-triggered <a class="header-anchor" href="#_8-level-triggered-与-edge-triggered" aria-label="Permalink to &quot;8. level-triggered 与 edge-triggered&quot;">​</a></h2><p>level-triggered 是默认：只要 fd 仍可读，后续 wait 继续报告。代码较易正确，但未消费事件可能反复唤醒。</p><p>edge-triggered 只在状态变化时通知。fd 必须非阻塞，并在收到通知后循环 accept/read/write，直到 <code>EAGAIN</code>；否则缓冲区仍有数据但没有新边缘，连接会停滞。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>on EPOLLIN:</span></span>
<span class="line"><span>  loop:</span></span>
<span class="line"><span>    n = read(fd)</span></span>
<span class="line"><span>    if n &gt; 0: append_to_frame_buffer(n bytes); continue</span></span>
<span class="line"><span>    if n == 0: close_connection(); break</span></span>
<span class="line"><span>    if errno == EAGAIN: break</span></span>
<span class="line"><span>    if errno == EINTR: continue_with_deadline_check</span></span>
<span class="line"><span>    close_with_error(); break</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这段是算法，不放入 C 围栏。完整实现还需解析消息 framing、限制 buffer、处理取消和保证 fd 不在回调期间被复用。</p><h2 id="_9-监听与连接状态机" tabindex="-1">9. 监听与连接状态机 <a class="header-anchor" href="#_9-监听与连接状态机" aria-label="Permalink to &quot;9. 监听与连接状态机&quot;">​</a></h2><p>非阻塞服务器的核心循环：监听 fd 可读时反复 accept 到 EAGAIN；为每个连接创建输入/输出缓冲；可读时解析零到多个完整消息；有待发送数据才订阅 <code>EPOLLOUT</code>，发送完取消写关注，避免持续可写造成 busy loop。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stateDiagram-v2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [*] --&gt; Reading: accept</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Reading --&gt; Reading: 部分消息</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Reading --&gt; Processing: 完整消息</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Processing --&gt; Writing: 生成响应</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Writing --&gt; Writing: 部分写或EAGAIN</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Writing --&gt; Reading: 响应写完且保持连接</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Reading --&gt; Closing: EOF、超时或协议错误</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Writing --&gt; Closing: 写错误或队列超限</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Closing --&gt; [*]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>TCP 是字节流，epoll 不提供消息边界。长度前缀必须限制最大长度；分隔符协议要限制未遇到分隔符时的累计字节；HTTP 需要成熟 parser 防止请求走私和资源耗尽。</p><h2 id="_10-race、惊群和生命周期" tabindex="-1">10. race、惊群和生命周期 <a class="header-anchor" href="#_10-race、惊群和生命周期" aria-label="Permalink to &quot;10. race、惊群和生命周期&quot;">​</a></h2><p>多个线程等待同一 epoll/监听 fd 时可能同时被唤醒；<code>EPOLLEXCLUSIVE</code> 可在特定场景减少惊群，但并不替代负载分配设计。<code>EPOLLONESHOT</code> 可把一个连接一次交给一个 worker，处理后 rearm。</p><p>关闭前应从事件循环中移除/标记连接，让晚到事件通过 generation token 或对象身份验证。把 fd 数字直接放到异步队列，稍后处理时可能已指向新连接。</p><h2 id="_11-完整案例-连接数增长后请求停滞" tabindex="-1">11. 完整案例：连接数增长后请求停滞 <a class="header-anchor" href="#_11-完整案例-连接数增长后请求停滞" aria-label="Permalink to &quot;11. 完整案例：连接数增长后请求停滞&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>edge-triggered epoll 服务在 5000 连接后部分连接永远无响应。</li><li>CPU 低、fd 未耗尽；客户端发 64 KiB 消息。</li><li>服务每次 EPOLLIN 只调用一次 <code>read(fd, buf, 4096)</code>。</li></ul><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li>用固定测试消息和连接数复现，记录每连接已收字节。</li><li><code>ss -tin</code> 显示服务接收队列仍有数据，但应用不再 read。</li><li>检查事件逻辑确认使用 EPOLLET，单次只读取 4096 字节。</li><li>改为非阻塞循环 read 直到 EAGAIN，同时保留 EOF、EINTR 和硬错误分支。</li><li>加入最大消息 1 MiB、每连接输出 2 MiB 和空闲 deadline，防止无界内存。</li><li>对部分写应用同样的游标逻辑，仅在队列非空订阅 EPOLLOUT。</li></ol><h3 id="输出与验证" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>64 KiB 消息全部解析并响应；1、4095、4096、4097、65536 字节分片测试通过；连接数增长时无 busy loop，fd 数回到基线。故意发送超过 1 MiB 输入得到明确协议错误并关闭连接。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若已 drain 到 EAGAIN 仍停滞，检查事件 rearm、fd 复用、应用 framing、输出队列和对端半关闭。若 <code>EMFILE</code>，先定位泄漏并实施 accept 失败策略；仅调高 limit 会把故障推迟并增加内存风险。</p><h2 id="_12-常见错误" tabindex="-1">12. 常见错误 <a class="header-anchor" href="#_12-常见错误" aria-label="Permalink to &quot;12. 常见错误&quot;">​</a></h2><ul><li>把 fd 当全局唯一、不复用的资源 ID。</li><li>忘记 <code>CLOEXEC</code>，让子进程意外持有监听或 pipe，导致无法 EOF/重启。</li><li>认为一次可读代表完整消息，或一次 write 能发送全部缓冲。</li><li>edge-triggered 没有 drain 到 EAGAIN。</li><li>永久订阅 EPOLLOUT，因 socket 通常可写而忙循环。</li><li>close 后重试 close，误伤复用 fd。</li><li>只提高 nofile，不计算连接的内存与下游预算。</li></ul><h2 id="_13-练习与完成标准" tabindex="-1">13. 练习与完成标准 <a class="header-anchor" href="#_13-练习与完成标准" aria-label="Permalink to &quot;13. 练习与完成标准&quot;">​</a></h2><ol><li>用 pipe 或 socketpair 验证非阻塞读的四个分支：数据、EAGAIN、EOF、错误。</li><li>画出一个长度前缀协议的部分读/部分写状态机，设置输入和输出上限。</li><li>比较 level 与 edge 模式下只读一次的行为，说明 edge 为什么停滞。</li><li>完成标准：测试包含 fd 复用、连接 half-close、超限、空闲超时与 4096 边界；没有 busy loop 或泄漏。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://man7.org/linux/man-pages/man2/open.2.html" target="_blank" rel="noreferrer">Linux man-pages：open(2)、fcntl(2)、close(2)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man7/epoll.7.html" target="_blank" rel="noreferrer">Linux man-pages：epoll(7)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man2/epoll_ctl.2.html" target="_blank" rel="noreferrer">Linux man-pages：epoll_ctl(2)、epoll_wait(2)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man2/poll.2.html" target="_blank" rel="noreferrer">Linux man-pages：select(2)、poll(2)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man5/proc_pid_fd.5.html" target="_blank" rel="noreferrer">Linux man-pages：proc_pid_fd(5)、getrlimit(2)</a>（访问日期：2026-07-17）</li></ul>`,59)])])}const g=s(l,[["render",t]]);export{k as __pageData,g as default};
